import yaml

# Read the original YAML
with open('curriculum/l2-uk-en/a1/activities/imperative-and-requests.yaml', 'r', encoding='utf-8') as f:
    data = yaml.safe_load(f)

# The file has 8 activities now. The last 3 are the ones I added.
# Activity 5 (index 5): quiz
# Activity 6: match-up
# Activity 7: fill-in

# Fix Quiz (needs 8 items, currently 4)
quiz_items = data[5]['items']
quiz_items.extend([
  {
    'question': "Which word means 'please' in Ukrainian?",
    'explanation': "Будь ласка is the universal polite phrase.",
    'options': [
      {'text': 'будь ласка', 'correct': True},
      {'text': 'дякую', 'correct': False},
      {'text': 'не треба', 'correct': False},
      {'text': 'прошу', 'correct': False}
    ]
  },
  {
    'question': "How do you say 'Do not give' formally?",
    'explanation': "Use 'не' before the formal imperative 'дайте'.",
    'options': [
      {'text': 'не дайте', 'correct': True},
      {'text': 'не дай', 'correct': False},
      {'text': 'не дати', 'correct': False},
      {'text': 'дайте не', 'correct': False}
    ]
  },
  {
    'question': "What is the informal negative command for 'write'?",
    'explanation': "Use 'не' before 'пиши'.",
    'options': [
      {'text': 'не пиши', 'correct': True},
      {'text': 'не пишіть', 'correct': False},
      {'text': 'не писати', 'correct': False},
      {'text': 'пиши не', 'correct': False}
    ]
  },
  {
    'question': "How do you ask someone politely to wait (formal)?",
    'explanation': "Combine 'чекайте' with 'будь ласка'.",
    'options': [
      {'text': 'чекайте, будь ласка', 'correct': True},
      {'text': 'чекай, будь ласка', 'correct': False},
      {'text': 'чекати', 'correct': False},
      {'text': 'не чекайте', 'correct': False}
    ]
  }
])

# Fix Match-up (needs 8 pairs, currently 5)
match_pairs = data[6]['pairs']
match_pairs.extend([
  {'left': 'Read, please.', 'right': 'Читайте, будь ласка.'},
  {'left': 'Write here, please.', 'right': 'Пишіть тут, будь ласка.'},
  {'left': 'Wait, please.', 'right': 'Чекайте, будь ласка.'}
])

# Fix Fill-in (needs 8 items, currently 4)
fill_items = data[7]['items']
# Also, let's explicitly make "Не" a string to fix the schema error
for item in fill_items:
    if item['answer'] == 'Не':
        item['answer'] = 'Не'
    item['options'] = [str(opt) for opt in item['options']]

fill_items.extend([
  {
    'sentence': "___ слухай це!",
    'answer': 'Не',
    'options': ['Не', 'Ні', 'Так', 'Нічого']
  },
  {
    'sentence': "Не ___ сюди, будь ласка.",
    'answer': 'ідіть',
    'options': ['ідіть', 'іди', 'іти', 'іду']
  },
  {
    'sentence': "Не ___ це.",
    'answer': 'читай',
    'options': ['читай', 'читати', 'читаю', 'читаєте']
  },
  {
    'sentence': "___ чекай мене.",
    'answer': 'Не',
    'options': ['Не', 'Ні', 'Без', 'Ніколи']
  }
])

# Save back to YAML
with open('curriculum/l2-uk-en/a1/activities/imperative-and-requests.yaml', 'w', encoding='utf-8') as f:
    yaml.dump(data, f, allow_unicode=True, sort_keys=False, default_flow_style=False)

